    }
    return self;
}

- (void)setVapp:(WBVAppModel *)vapp {
    if (_vapp != vapp) {
        [_vapp removeStatusObserver:self];
        _vapp = vapp;
        [_vapp addStatusObserver:self];

        if (!vapp.featureStatusInfo) {
            WBVAppFeatureStatus *featureStatusInfo = [[WBVAppFeatureStatus alloc] init];
            featureStatusInfo.isLockSwitchOn = NO;
            featureStatusInfo.isNotificationSwitchOn = NO;
            featureStatusInfo.isDisguiseSwitchOn = NO;
            featureStatusInfo.isPretenseSwitchOn = NO;
            featureStatusInfo.isOneClickSwitchOn = NO;
            vapp.featureStatusInfo = featureStatusInfo;
        }

        if (!vapp.errorInfo) {
            WBVAppErrorInfo *errorInfo = [[WBVAppErrorInfo alloc] init];
            errorInfo.errorType = WBVappStatusNone;
            errorInfo.errorDomain = @"";
            errorInfo.errorCode = 0;
            errorInfo.errorMessage = @"";
            vapp.errorInfo = errorInfo;
        }

        BOOL isServerNotificationSupported = [[WBBenefitManager sharedManager] isBenefitAvailable:WBUserBenefitNotification];
        BOOL isServerLockSupported = [[WBBenefitManager sharedManager] isBenefitAvailable:WBUserBenefitLock];
        BOOL isServerDisguiseSupported = [[WBBenefitManager sharedManager] isBenefitAvailable:WBUserBenefitDisguise];
        BOOL isServerPretenseSupported = [[WBBenefitManager sharedManager] isBenefitAvailable:WBUserBenefitPretense];
        BOOL isServerOneClickSupported = [[WBBenefitManager sharedManager] isBenefitAvailable:WBUserBenefitOneClick];
        vapp.featureStatusInfo.isNotificationSwitchOn = (isServerNotificationSupported && vapp.featureStatusInfo.isNotificationSwitchOn);
        vapp.featureStatusInfo.isLockSwitchOn = (isServerLockSupported && vapp.featureStatusInfo.isLockSwitchOn);
        vapp.featureStatusInfo.isDisguiseSwitchOn = (isServerDisguiseSupported && vapp.featureStatusInfo.isDisguiseSwitchOn);
        vapp.featureStatusInfo.isPretenseSwitchOn = (isServerPretenseSupported && vapp.featureStatusInfo.isPretenseSwitchOn);
        vapp.featureStatusInfo.isOneClickSwitchOn = (isServerOneClickSupported && vapp.featureStatusInfo.isOneClickSwitchOn);

        [WBVAppManager.sharedManager saveBackgroundSetting:vapp.featureStatusInfo.isNotificationSwitchOn forVApp:vapp];
        if (!vapp.featureStatusInfo.isDisguiseSwitchOn) {
            [WBVAppManager.sharedManager saveCustomIcon:nil customName:nil forVApp:vapp];
        }

        [self updateCell];
    } else {
        [self updateCell];
    }
}

- (void)setParentVC:(UIViewController<WBHomeVappFeatureViewDelegate> *)parentVC {
    _parentVC = parentVC;
    for (WBHomeVappFeatureView *view in self.selectedFeatureViews) {
        view.delegate = parentVC;
