                break;
            case WBHomeVappFeatureCornerStyleTop:
                self.layer.cornerRadius = r;
                self.layer.maskedCorners = kCALayerMinXMinYCorner | kCALayerMaxXMinYCorner;
                break;
            case WBHomeVappFeatureCornerStyleMiddle:
                self.layer.cornerRadius = 0;
